namespace sv_49df1d29adec485e9016a9f56170f7a9.Models;

public class WizardState
{
    // Step 1 – Personal Info
    public string Name { get; set; } = string.Empty;
    public string Email { get; set; } = string.Empty;

    // Step 2 – Experience
    public List<JobEntry> Jobs { get; set; } = [];

    // Step 3 – References
    public List<ReferenceContact> References { get; set; } = [];

    // Tracking
    public HashSet<int> CompletedSteps { get; set; } = [];

    public static readonly (string Path, string Title)[] Steps =
    [
        ("/apply/personal-info", "Personal Info"),
        ("/apply/experience", "Experience"),
        ("/apply/references", "References"),
        ("/apply/review", "Review"),
    ];

    public int GetStepIndex(string path)
    {
        for (int i = 0; i < Steps.Length; i++)
        {
            if (path.Equals(Steps[i].Path, StringComparison.OrdinalIgnoreCase))
                return i;
        }

        return -1;
    }
}

public class JobEntry
{
    public string Company { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Years { get; set; } = string.Empty;
}

public class ReferenceContact
{
    public string Name { get; set; } = string.Empty;
    public string Relationship { get; set; } = string.Empty;
    public string Phone { get; set; } = string.Empty;
}

@page "/apply/personal-info"
@rendermode InteractiveServer
@using sv_49df1d29adec485e9016a9f56170f7a9.Models
@inject CascadingValueSource<WizardState> WizardSource
@inject NavigationManager Nav

<PageTitle>Step 1 – Personal Info</PageTitle>

<h1>Personal Information</h1>

<EditForm Model="Wizard" OnValidSubmit="Next" FormName="personal-info">
    <div class="mb-3">
        <label class="form-label">Full Name</label>
        <InputText class="form-control" @bind-Value="Wizard!.Name" />
    </div>
    <div class="mb-3">
        <label class="form-label">Email</label>
        <InputText class="form-control" @bind-Value="Wizard!.Email" />
    </div>
    <button type="submit" class="btn btn-primary">Next &rarr;</button>
</EditForm>

@code {
    [CascadingParameter]
    private WizardState? Wizard { get; set; }

    private async Task Next()
    {
        Wizard!.CompletedSteps.Add(0);
        await WizardSource.NotifyChangedAsync(Wizard);
        Nav.NavigateTo("/apply/experience");
    }
}

@page "/apply/experience"
@rendermode InteractiveServer
@using sv_49df1d29adec485e9016a9f56170f7a9.Models
@inject CascadingValueSource<WizardState> WizardSource
@inject NavigationManager Nav

<PageTitle>Step 2 – Experience</PageTitle>

<h1>Work Experience</h1>

@for (int i = 0; i < Wizard!.Jobs.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Job @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveJob(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Company</label>
            <input class="form-control" @bind="Wizard.Jobs[index].Company" />
        </div>
        <div class="mb-2">
            <label class="form-label">Title</label>
            <input class="form-control" @bind="Wizard.Jobs[index].Title" />
        </div>
        <div class="mb-2">
            <label class="form-label">Years</label>
            <input class="form-control" @bind="Wizard.Jobs[index].Years" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddJob">+ Add Job</button>

<div>
    <button type="button" class="btn btn-secondary me-2" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    [CascadingParameter]
    private WizardState? Wizard { get; set; }

    private void AddJob() => Wizard!.Jobs.Add(new JobEntry());

    private void RemoveJob(int index) => Wizard!.Jobs.RemoveAt(index);

    private async Task Next()
    {
        Wizard!.CompletedSteps.Add(1);
        await WizardSource.NotifyChangedAsync(Wizard);
        Nav.NavigateTo("/apply/references");
    }

    private void Back() => Nav.NavigateTo("/apply/personal-info");
}

@page "/apply/references"
@rendermode InteractiveServer
@using sv_49df1d29adec485e9016a9f56170f7a9.Models
@inject CascadingValueSource<WizardState> WizardSource
@inject NavigationManager Nav

<PageTitle>Step 3 – References</PageTitle>

<h1>References</h1>

@for (int i = 0; i < Wizard!.References.Count; i++)
{
    var index = i;
    <div class="card mb-3 p-3">
        <div class="d-flex justify-content-between align-items-center mb-2">
            <strong>Reference @(index + 1)</strong>
            <button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveRef(index)">Remove</button>
        </div>
        <div class="mb-2">
            <label class="form-label">Name</label>
            <input class="form-control" @bind="Wizard.References[index].Name" />
        </div>
        <div class="mb-2">
            <label class="form-label">Relationship</label>
            <input class="form-control" @bind="Wizard.References[index].Relationship" />
        </div>
        <div class="mb-2">
            <label class="form-label">Phone</label>
            <input class="form-control" @bind="Wizard.References[index].Phone" />
        </div>
    </div>
}

<button type="button" class="btn btn-outline-secondary mb-3" @onclick="AddRef">+ Add Reference</button>

<div>
    <button type="button" class="btn btn-secondary me-2" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-primary" @onclick="Next">Next &rarr;</button>
</div>

@code {
    [CascadingParameter]
    private WizardState? Wizard { get; set; }

    private void AddRef() => Wizard!.References.Add(new ReferenceContact());

    private void RemoveRef(int index) => Wizard!.References.RemoveAt(index);

    private async Task Next()
    {
        Wizard!.CompletedSteps.Add(2);
        await WizardSource.NotifyChangedAsync(Wizard);
        Nav.NavigateTo("/apply/review");
    }

    private void Back() => Nav.NavigateTo("/apply/experience");
}

@page "/apply/review"
@rendermode InteractiveServer
@using sv_49df1d29adec485e9016a9f56170f7a9.Models
@inject NavigationManager Nav

<PageTitle>Step 4 – Review</PageTitle>

<h1>Review Your Application</h1>

<h4>Personal Information</h4>
<dl class="row">
    <dt class="col-sm-3">Name</dt>
    <dd class="col-sm-9">@Wizard!.Name</dd>
    <dt class="col-sm-3">Email</dt>
    <dd class="col-sm-9">@Wizard.Email</dd>
</dl>

<h4>Work Experience</h4>
@if (Wizard.Jobs.Count == 0)
{
    <p class="text-muted">No jobs entered.</p>
}
else
{
    <table class="table">
        <thead>
            <tr><th>Company</th><th>Title</th><th>Years</th></tr>
        </thead>
        <tbody>
            @foreach (var job in Wizard.Jobs)
            {
                <tr><td>@job.Company</td><td>@job.Title</td><td>@job.Years</td></tr>
            }
        </tbody>
    </table>
}

<h4>References</h4>
@if (Wizard.References.Count == 0)
{
    <p class="text-muted">No references entered.</p>
}
else
{
    <table class="table">
        <thead>
            <tr><th>Name</th><th>Relationship</th><th>Phone</th></tr>
        </thead>
        <tbody>
            @foreach (var r in Wizard.References)
            {
                <tr><td>@r.Name</td><td>@r.Relationship</td><td>@r.Phone</td></tr>
            }
        </tbody>
    </table>
}

<div>
    <button type="button" class="btn btn-secondary me-2" @onclick="Back">&larr; Back</button>
    <button type="button" class="btn btn-success" @onclick="Submit">Submit Application</button>
</div>

@code {
    [CascadingParameter]
    private WizardState? Wizard { get; set; }

    private void Back() => Nav.NavigateTo("/apply/references");

    private void Submit()
    {
        // TODO: persist the application to a database
        Nav.NavigateTo("/");
    }
}

