 ﻿@inherits LayoutComponentBase
 @using sv_49df1d29adec485e9016a9f56170f7a9.Models
 @inject NavigationManager Nav

 <div class="page">
     <div class="sidebar">
         <NavMenu />
     </div>

     <main>
         <div class="top-row px-4">
             @if (IsWizardPage)
             {
                 <nav aria-label="Application progress" class="d-flex align-items-center gap-3 w-100">
                     @for (int i = 0; i < WizardState.Steps.Length; i++)
                     {
                         var step = WizardState.Steps[i];
                         var isCurrent = i == CurrentStep;
                         var isCompleted = Wizard?.CompletedSteps.Contains(i) == true;

                         <a href="@step.Path"
                            class="text-decoration-none @(isCurrent ? "fw-bold text-primary" : isCompleted ? "text-success" : "text-muted")">
                             <span class="badge @(isCurrent ? "bg-primary" : isCompleted ? "bg-success" : "bg-secondary") me-1">
                                 @(i + 1)
                             </span>
                             @step.Title
                         </a>

                         @if (i < WizardState.Steps.Length - 1)
                         {
                             <span class="text-muted">&rsaquo;</span>
                         }
                     }
                     <span class="ms-auto text-muted">Step @(CurrentStep + 1) of @WizardState.Steps.Length</span>
                 </nav>
             }
             else
             {
                 <a href="https://learn.microsoft.com/aspnet/core/" target="_blank">About</a>
             }
         </div>

         <article class="content px-4">
             @Body
         </article>
     </main>
 </div>

 <div id="blazor-error-ui" data-nosnippet>
     An unhandled error has occurred.
     <a href="." class="reload">Reload</a>
     <span class="dismiss">🗙</span>
 </div>

 @code {
     [CascadingParameter]
     private WizardState? Wizard { get; set; }

     private int CurrentStep =>
         Wizard?.GetStepIndex(new Uri(Nav.Uri).AbsolutePath) ?? -1;

     private bool IsWizardPage => CurrentStep >= 0;
 }

